blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>pięć podstawowych spójników</strong> w języku angielskim: and, but, or, because i so. Zobaczysz, co znaczą i jak ich naturalnie używać.",
    "rules": [
        {
            "label": "And",
            "color": "emerald",
            "text": "<strong>i, oraz</strong> — łączy podobne informacje:",
            "example": "I like tea and coffee."
        },
        {
            "label": "But",
            "color": "rose",
            "text": "<strong>ale, jednak</strong> — pokazuje kontrast:",
            "example": "I like tea, but I don't like coffee."
        },
        {
            "label": "Or",
            "color": "blue",
            "text": "<strong>lub, albo</strong> — pokazuje wybór:",
            "example": "Do you want tea or coffee?"
        },
        {
            "label": "Because",
            "color": "amber",
            "text": "<strong>ponieważ, bo</strong> — wyjaśnia przyczynę:",
            "example": "I stayed home because it was raining."
        },
        {
            "label": "So",
            "color": "purple",
            "text": "<strong>więc, dlatego</strong> — pokazuje skutek:",
            "example": "It was raining, so I stayed home."
        }
    ]
}

{
    "title": "1. Czym są spójniki?",
    "intro": "Spójniki (conjunctions) łączą różne elementy wypowiedzi:",
    "items": [
        {
            "label": "Wyrazy",
            "title": "Words",
            "subtitle": "tea and coffee / big but cheap"
        },
        {
            "label": "Wyrażenia",
            "title": "Phrases",
            "subtitle": "in the morning or in the evening"
        },
        {
            "label": "Zdania",
            "title": "Clauses",
            "subtitle": "I came home and I cooked dinner."
        }
    ]
}

{
    "title": "2. AND — i, oraz (dodawanie)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "emerald",
            "description": "<strong>And</strong> łączy podobne albo równorzędne elementy. Dodaje kolejną informację.",
            "examples": [
                {
                    "en": "I have a cat and a dog.",
                    "ua": "Mam kota i psa."
                },
                {
                    "en": "She is smart and beautiful.",
                    "ua": "Jest mądra i piękna."
                },
                {
                    "en": "I came home and watched TV.",
                    "ua": "Wróciłem do domu i oglądałem telewizję."
                }
            ]
        },
        {
            "label": "Łączenie wyrazów",
            "color": "sky",
            "description": "<strong>And</strong> może łączyć rzeczowniki, przymiotniki i czasowniki.",
            "examples": [
                {
                    "en": "bread and butter",
                    "ua": "chleb i masło"
                },
                {
                    "en": "big and comfortable",
                    "ua": "duży i wygodny"
                },
                {
                    "en": "run and jump",
                    "ua": "biegać i skakać"
                }
            ]
        },
        {
            "label": "Łączenie zdań",
            "color": "amber",
            "description": "Gdy <strong>and</strong> łączy dwa pełne zdania, przed spójnikiem często pojawia się przecinek.",
            "examples": [
                {
                    "en": "I woke up early, and I went for a run.",
                    "ua": "Wstałem wcześnie i poszedłem pobiegać."
                },
                {
                    "en": "She cooked dinner, and he washed the dishes.",
                    "ua": "Ona ugotowała obiad, a on pozmywał naczynia."
                }
            ],
            "note": "W krótkich zdaniach przecinek przed <strong>and</strong> bywa pomijany."
        }
    ]
}

{
    "title": "3. BUT — ale, jednak (kontrast)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "rose",
            "description": "<strong>But</strong> pokazuje kontrast, przeciwstawienie albo nieoczekiwany rezultat.",
            "examples": [
                {
                    "en": "I like coffee, but I don't like tea.",
                    "ua": "Lubię kawę, ale nie lubię herbaty."
                },
                {
                    "en": "She is young but very experienced.",
                    "ua": "Jest młoda, ale bardzo doświadczona."
                },
                {
                    "en": "I tried hard, but I couldn't finish.",
                    "ua": "Bardzo się starałem, ale nie dałem rady skończyć."
                }
            ]
        },
        {
            "label": "Przeciwstawienie",
            "color": "sky",
            "description": "<strong>But</strong> wprowadza informację sprzeczną z tym, czego można było się spodziewać.",
            "examples": [
                {
                    "en": "The hotel was expensive, but it was worth it.",
                    "ua": "Hotel był drogi, ale było warto."
                },
                {
                    "en": "He's rich, but he's not happy.",
                    "ua": "Jest bogaty, ale nie jest szczęśliwy."
                }
            ]
        },
        {
            "label": "Interpunkcja",
            "color": "amber",
            "description": "Przed <strong>but</strong> zwykle stawiamy przecinek, gdy łączy dwa pełne zdania.",
            "examples": [
                {
                    "en": "I wanted to go, but it was too late.",
                    "ua": "Chciałem iść, ale było już za późno."
                }
            ],
            "note": "Bez przecinka: <em>small but cozy</em>, gdy łączysz tylko słowa lub krótkie grupy wyrazów."
        }
    ]
}

{
    "title": "4. OR — lub, albo (wybór)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "blue",
            "description": "<strong>Or</strong> pokazuje alternatywę albo wybór między dwiema lub więcej opcjami.",
            "examples": [
                {
                    "en": "Do you want tea or coffee?",
                    "ua": "Chcesz herbatę czy kawę?"
                },
                {
                    "en": "We can go today or tomorrow.",
                    "ua": "Możemy pójść dziś albo jutro."
                },
                {
                    "en": "Is it true or false?",
                    "ua": "To prawda czy fałsz?"
                }
            ]
        },
        {
            "label": "W pytaniach",
            "color": "sky",
            "description": "<strong>Or</strong> często pojawia się w pytaniach, kiedy proponujemy wybór.",
            "examples": [
                {
                    "en": "Do you prefer cats or dogs?",
                    "ua": "Wolisz koty czy psy?"
                },
                {
                    "en": "Should I call or text you?",
                    "ua": "Mam do ciebie zadzwonić czy napisać?"
                }
            ]
        },
        {
            "label": "W przeczeniach",
            "color": "amber",
            "description": "W zdaniach przeczących po angielsku często używamy <strong>or</strong> zamiast <strong>and</strong>.",
            "examples": [
                {
                    "en": "I don't like tea or coffee.",
                    "ua": "Nie lubię ani herbaty, ani kawy."
                },
                {
                    "en": "She doesn't eat meat or fish.",
                    "ua": "Ona nie je mięsa ani ryb."
                }
            ],
            "note": "Porównaj: <em>I like tea and coffee</em> oraz <em>I don't like tea or coffee</em>."
        }
    ]
}

{
    "title": "5. BECAUSE — ponieważ, bo (przyczyna)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "amber",
            "description": "<strong>Because</strong> wprowadza przyczynę i odpowiada na pytanie „dlaczego?”.",
            "examples": [
                {
                    "en": "I stayed home because it was raining.",
                    "ua": "Zostałem w domu, bo padał deszcz."
                },
                {
                    "en": "She's tired because she worked all day.",
                    "ua": "Jest zmęczona, bo pracowała cały dzień."
                },
                {
                    "en": "I can't come because I'm busy.",
                    "ua": "Nie mogę przyjść, bo jestem zajęty."
                }
            ]
        },
        {
            "label": "Pozycja w zdaniu",
            "color": "sky",
            "description": "Część zdania z <strong>because</strong> może stać na końcu albo na początku wypowiedzi.",
            "examples": [
                {
                    "en": "I stayed home because it was raining.",
                    "ua": "przyczyna na końcu"
                },
                {
                    "en": "Because it was raining, I stayed home.",
                    "ua": "przyczyna na początku, z przecinkiem"
                }
            ]
        },
        {
            "label": "Because vs because of",
            "color": "emerald",
            "description": "<strong>Because</strong> łączy się ze zdaniem, a <strong>because of</strong> z rzeczownikiem lub grupą rzeczownikową.",
            "examples": [
                {
                    "en": "I stayed home because it was raining.",
                    "ua": "because + zdanie"
                },
                {
                    "en": "I stayed home because of the rain.",
                    "ua": "because of + rzeczownik"
                }
            ],
            "note": "Nie myl <em>because</em> z <em>because of</em>."
        }
    ]
}

{
    "title": "6. SO — więc, dlatego (skutek)",
    "sections": [
        {
            "label": "Znaczenie",
            "color": "purple",
            "description": "<strong>So</strong> wprowadza skutek lub rezultat wcześniejszej sytuacji.",
            "examples": [
                {
                    "en": "It was raining, so I stayed home.",
                    "ua": "Padał deszcz, więc zostałem w domu."
                },
                {
                    "en": "I was hungry, so I made a sandwich.",
                    "ua": "Byłem głodny, więc zrobiłem sobie kanapkę."
                },
                {
                    "en": "She studied hard, so she passed the exam.",
                    "ua": "Dużo się uczyła, więc zdała egzamin."
                }
            ]
        },
        {
            "label": "Because i so",
            "color": "sky",
            "description": "<strong>Because</strong> mówi o przyczynie, a <strong>so</strong> o skutku. To te same informacje, ale w innej kolejności.",
            "examples": [
                {
                    "en": "I stayed home because it was raining.",
                    "ua": "skutek + przyczyna"
                },
                {
                    "en": "It was raining, so I stayed home.",
                    "ua": "przyczyna + skutek"
                }
            ]
        },
        {
            "label": "Interpunkcja",
            "color": "amber",
            "description": "Przed <strong>so</strong> zwykle stawiamy przecinek, gdy łączy dwa pełne zdania.",
            "examples": [
                {
                    "en": "The shop was closed, so we went home.",
                    "ua": "Sklep był zamknięty, więc wróciliśmy do domu."
                },
                {
                    "en": "I don't have money, so I can't buy it.",
                    "ua": "Nie mam pieniędzy, więc nie mogę tego kupić."
                }
            ]
        }
    ]
}

{
    "title": "7. Tabela porównawcza",
    "intro": "Pięć podstawowych spójników i ich funkcje:",
    "rows": [
        {
            "en": "AND",
            "ua": "i, oraz",
            "note": "dodawanie: I like tea and coffee."
        },
        {
            "en": "BUT",
            "ua": "ale, jednak",
            "note": "kontrast: I like tea, but I don't like coffee."
        },
        {
            "en": "OR",
            "ua": "lub, albo",
            "note": "wybór: Do you want tea or coffee?"
        },
        {
            "en": "BECAUSE",
            "ua": "ponieważ, bo",
            "note": "przyczyna: I stayed home because it was raining."
        },
        {
            "en": "SO",
            "ua": "więc, dlatego",
            "note": "skutek: It was raining, so I stayed home."
        }
    ],
    "warning": "📌 <strong>And, but, or</strong> to spójniki współrzędne. <strong>Because</strong> wprowadza przyczynę, a <strong>so</strong> skutek."
}

{
    "title": "8. Interpunkcja ze spójnikami",
    "intro": "Kiedy warto postawić przecinek przed spójnikiem:",
    "rows": [
        {
            "en": "Between words",
            "ua": "Między wyrazami",
            "note": "bez przecinka: tea and coffee, small but cozy"
        },
        {
            "en": "Between clauses",
            "ua": "Między zdaniami składowymi",
            "note": "z przecinkiem: I came home, and she left."
        },
        {
            "en": "Short clauses",
            "ua": "W krótkich zdaniach",
            "note": "przecinek bywa opcjonalny: I came and she left."
        }
    ],
    "warning": "⚠️ Przed <strong>but</strong> i <strong>so</strong> przecinek pojawia się bardzo często, gdy łączymy dwa pełne zdania."
}

{
    "title": "9. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Mylenie because i because of.",
            "wrong": "I stayed home because of it was raining.",
            "right": "✅ <span class=\"font-mono\">I stayed home because it was raining.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie and zamiast or w przeczeniu.",
            "wrong": "I don't like tea and coffee.",
            "right": "✅ <span class=\"font-mono\">I don't like tea or coffee.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Brak przecinka po because na początku zdania.",
            "wrong": "Because it was raining I stayed home.",
            "right": "✅ <span class=\"font-mono\">Because it was raining, I stayed home.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Użycie so that zamiast so do zwykłego skutku.",
            "wrong": "I was tired so that I went to bed.",
            "right": "✅ <span class=\"font-mono\">I was tired, so I went to bed.</span>"
        }
    ]
}

{
    "title": "11. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz właściwy spójnik",
    "select_intro": "Uzupełnij zdania odpowiednim spójnikiem.",
    "selects": [
        {
            "label": "I like tea ___ coffee. (and / but / or)",
            "prompt": "Który spójnik pasuje?"
        },
        {
            "label": "She is smart ___ she doesn't study much. (and / but / because)",
            "prompt": "Który spójnik pasuje?"
        },
        {
            "label": "Do you want pizza ___ pasta? (and / but / or)",
            "prompt": "Który spójnik pasuje?"
        },
        {
            "label": "I stayed home ___ it was raining. (but / because / so)",
            "prompt": "Który spójnik pasuje?"
        }
    ],
    "options": [
        "and",
        "but",
        "or",
        "because",
        "so"
    ],
    "input_title": "Ćwiczenie 2. Połącz zdania",
    "input_intro": "Połącz dwa zdania za pomocą odpowiedniego spójnika.",
    "inputs": [
        {
            "before": "I was tired. I went to bed. (so) →",
            "after": ""
        },
        {
            "before": "She's rich. She's not happy. (but) →",
            "after": ""
        },
        {
            "before": "I can't come. I'm busy. (because) →",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź i popraw błąd w użyciu spójnika.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I don't like tea and coffee.",
            "example_target": "I don't like tea or coffee."
        },
        {
            "original": "1. I stayed home because of it was cold.",
            "placeholder": "Popraw błąd"
        },
        {
            "original": "2. Because I was hungry I made lunch.",
            "placeholder": "Popraw błąd z interpunkcją"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Conjunctions — and, but, or, because, so",
            "current": true
        },
        {
            "label": "Imperatives — tryb rozkazujący",
            "current": false
        },
        {
            "label": "Sentence Types — typy zdań",
            "current": false
        },
        {
            "label": "Sentence Structure — budowa zdania (SVO)",
            "current": false
        },
        {
            "label": "Parts of Speech — części mowy",
            "current": false
        }
    ]
}
